# Demonstrates overloaded constructors and parent initialization

class DataSeries:
    name: str
    values: list[float]

    def __init__(self, name: str, values: list[float]):
        self.name = name
        self.values = values

    def average(self) -> float:
        total: float = 0.0
        count: int = len(self.values)
        if count == 0:
            return 0.0
        for v in self.values:
            total += v
        return total / float(count)

class RollingAverage(DataSeries):
    window_size: int

    # Primary constructor: full control
    def __init__(self, name: str, values: list[float], window: int):
        super().__init__(name, values)
        self.window_size = window

    # Delegating constructor: uses defaults
    def __init__(self, name: str, values: list[float]):
